ALTER TABLE public.projects ADD COLUMN IF NOT EXISTS parent_id uuid REFERENCES public.projects(id) ON DELETE SET NULL, ADD COLUMN IF NOT EXISTS is_favorite boolean NOT NULL DEFAULT false, ADD COLUMN IF NOT EXISTS archived_at timestamptz; ALTER TABLE public.tasks ADD COLUMN IF NOT EXISTS section_id uuid, ADD COLUMN IF NOT EXISTS deadline date, ADD COLUMN IF NOT EXISTS due_string text, ADD COLUMN IF NOT EXISTS recurrence_rule text; ALTER TABLE public.tasks ADD COLUMN IF NOT EXISTS due_datetime timestamp GENERATED ALWAYS AS (CASE WHEN due_date IS NULL THEN NULL ELSE (due_date + COALESCE(due_time, '00:00:00'::time)) END) STORED;